const row = $input.first().json;
const r = typeof row.result === 'string' ? JSON.parse(row.result) : row.result;
const action_token = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
  const r = (Math.random() * 16) | 0;
  const v = c === 'x' ? r : (r & 0x3) | 0x8;
  return v.toString(16);
});

const topError = r.errors?.[0]?.code || '—';
const text = `📊 Предложение по диалогу #${String(row.dialog_id).slice(0, 8)}

Сотрудник: ${row.employee_name} (${row.employee_id})
Магазин: ${row.store_id}

${r.manager_summary || 'Требуется разбор диалога.'}

⚠️ Ошибки: ${topError}
💡 Тренировка: ${(r.recommended_training || '').replace(/_/g, ' ')}

Подтвердите тренировку:`;

return [{
  json: {
    dialog_id: row.dialog_id,
    action_token,
    regional_chat_id: String(row.regional_chat_id).trim(),
    telegram_body: {
      chat_id: Number(row.regional_chat_id),
      text,
      reply_markup: {
        inline_keyboard: [[
          { text: '✅ Подтвердить тренировку', callback_data: `train:${action_token}` },
          { text: '❌ Не сейчас', callback_data: `skip:${action_token}` },
        ]],
      },
    },
  },
}];

