VALUES (
  '{{ $('CODE').item.json.dialog_id }}'::uuid,
  'regional',
  '{{ $('HTTP Request').first().json.result.message_id }}'

);

INSERT INTO pending_training_actions (action_token, dialog_id)
VALUES (
  '{{ $('CODE').first().json.action_token }}'::uuid,
'{{ $('CODE').first().json.dialog_id }}'::uuid
)
RETURNING action_token, dialog_id;
